return items.map(item => {
  const j = item.json || {};

  // Aceita variações de nome
  const horaMensagemRaw = j["Hora Mensagem"] ?? j["HoraMensagem"] ?? j["horaMensagem"] ?? null;
  const tempoAtualRaw   = j["Tempo atual"]   ?? j["TempoAtual"]   ?? j["tempoAtual"]   ?? null;

  const horaMensagemStr = typeof horaMensagemRaw === "string" ? horaMensagemRaw.trim() : horaMensagemRaw;
  const tempoAtualStr   = typeof tempoAtualRaw   === "string" ? tempoAtualRaw.trim()   : tempoAtualRaw;

  const base = {
    Nome: j["Nome"] ?? null,
    Id: j["Id"] ?? null,
    Telefone: j["Telefone"] ?? null,
    Email: j["Email"] ?? null,
    Idconversachatwoot: j["Idconversachatwoot"] ?? null,
    "Hora Mensagem": horaMensagemStr ?? null,
    "Tempo atual": tempoAtualStr ?? null
  };

  // Falta algum campo?
  if (!horaMensagemStr || !tempoAtualStr) {
    return {
      json: {
        ...base,
        error: "Um dos campos de data está vazio",
        _debug: {
          temHoraMensagem: Boolean(horaMensagemStr),
          temTempoAtual: Boolean(tempoAtualStr),
          chavesDisponiveis: Object.keys(j)
        }
      }
    };
  }

  // Remove dia da semana se vier "sexta-feira, 29 de agosto de 2025, 11:22"
  const cleanHoraMensagem = String(horaMensagemStr).replace(/^[^,]+,\s*/, "");
  const cleanTempoAtual   = String(tempoAtualStr).replace(/^[^,]+,\s*/, "");

  // Parser "DD de mês de YYYY, HH:mm"
  function parseDataPtBr(str) {
    const regex = /(\d{1,2}) de (\w+) de (\d{4}), (\d{2}):(\d{2})/;
    const meses = {
      "janeiro": 0, "fevereiro": 1, "março": 2, "marco": 2, "abril": 3,
      "maio": 4, "junho": 5, "julho": 6, "agosto": 7,
      "setembro": 8, "outubro": 9, "novembro": 10, "dezembro": 11
    };
    const m = str.match(regex);
    if (!m) return null;
    const [, dd, mesStr, yyyy, HH, MM] = m;
    const mes = meses[mesStr.toLowerCase()];
    if (mes === undefined) return null;
    return new Date(parseInt(yyyy,10), mes, parseInt(dd,10), parseInt(HH,10), parseInt(MM,10));
  }

  const dataMensagem = parseDataPtBr(cleanHoraMensagem);
  const dataAtual    = parseDataPtBr(cleanTempoAtual);

  if (!dataMensagem || !dataAtual) {
    return {
      json: {
        ...base,
        error: "Erro ao interpretar datas",
        _debug: { cleanHoraMensagem, cleanTempoAtual }
      }
    };
  }

  const diffMs       = dataAtual.getTime() - dataMensagem.getTime();
  const diffHoras    = Math.floor(diffMs / (1000 * 60 * 60));
  const diffMinutos  = Math.floor(diffMs / (1000 * 60)) % 60;

  return {
    json: {
      ...base,
      diferencaHoras: diffHoras,
      diferencaMinutos: diffMinutos
    }
  };
});

return items.map(item => {
  const timeZone = "America/Sao_Paulo";

  // Hora atual em São Paulo
  const nowSP = new Date(
    new Date().toLocaleString("en-US", { timeZone })
  );
  const hour = nowSP.getHours(); // 0–23

  // Janela permitida: 08:00 <= agora < 22:00
  const withinAllowedTime = hour >= 8 && hour < 22;

  return {
    json: {
      ...item.json,
      currentTime: nowSP.toLocaleString("pt-BR", { timeZone }),
      withinAllowedTime
    }
  };
});

