// Loop over input items and add a new field called 'myNewField' to the JSON of each one
const meses = {
  "janeiro": "01", "fevereiro": "02", "março": "03", "abril": "04",
  "maio": "05", "junho": "06", "julho": "07", "agosto": "08",
  "setembro": "09", "outubro": "10", "novembro": "11", "dezembro": "12"
};

let dados_filtados = [];
for (const item of $input.all()) {
  if (item.json["Data Entrada"] === item.json["Hora Mensagem"] &&
     (item.json["has_interaction"] || false) === false &&
     item.json.Idconversachatwoot !== null ) {
    const partes = item.json["Data Entrada"].split(", ");
    // partes[1] será "20 de fevereiro de 2026"
    const dataPartes = partes[1].split(" de ");
    const dia = dataPartes[0].padStart(2, '0');
    const mes = meses[dataPartes[1].toLowerCase()];
    const ano = dataPartes[2];
    const hora = partes[2]; // "13:21"
    item.json.data_iso = `${ano}-${mes}-${dia}T${hora}:00`;
    dados_filtados.push(item.json);
  }
}

return Object.values(dados_filtados);

